import java.util.Arrays;
public class LPSBuilder {
    public static int[] buildLPS(String pattern) {
        int m = pattern.length();
        int[] lps = new int[m];
        lps[0] = 0; // always 0
        int len = 0; // length of previous longest prefix-suffix
        int i = 1;
        while (i < m) {
            if (pattern.charAt(i) == pattern.charAt(len)) {
                lps[i] = len + 1;
                len++;
                i++;
            } else {
                if (len > 0) {
                    len = lps[len - 1]; // try shorter prefix
                    // don't increment i
                } else {
                    lps[i] = 0;
                    i++;
                }
            }
        }
        return lps;
    }
    public static void main(String[] args) {
        System.out.println(Arrays.toString(buildLPS("AABAAB")));  // [0,1,0,1,2,3]
        System.out.println(Arrays.toString(buildLPS("ABCABC"))); // [0,0,0,1,2,3]
        System.out.println(Arrays.toString(buildLPS("AAAA")));   // [0,1,2,3]
        System.out.println("O(m) time — no backtracking on len");
    }
}

