public class KMPSearch {
    static int[] buildLPS(String p) {
        int m=p.length(); int[] lps=new int[m]; int len=0, i=1;
        while(i<m){if(p.charAt(i)==p.charAt(len)){lps[i]=len+1;len++;i++;}else{if(len>0)len=lps[len-1];else{lps[i]=0;i++;}}}
        return lps;
    }
    public static int strStr(String text, String pattern) {
        if (pattern.isEmpty()) return 0;
        int n=text.length(), m=pattern.length();
        int[] lps = buildLPS(pattern);
        int i=0, j=0;
        while (i < n) {
            if (text.charAt(i) == pattern.charAt(j)) { i++; j++; }
            if (j == m) return i - m; // first occurrence
            else if (i < n && text.charAt(i) != pattern.charAt(j)) {
                if (j > 0) j = lps[j-1];
                else i++;
            }
        }
        return -1;
    }
    public static void main(String[] args) {
        System.out.println(strStr("hello", "ll"));          // 2
        System.out.println(strStr("aaaaa", "bba"));         // -1
        System.out.println(strStr("mississippi", "issip")); // 4
        System.out.println("O(n+m) KMP — text pointer never backtracks");
    }
}

