public class RepeatedSubstring {
    public static boolean repeatedSubstringPattern(String s) {
        // KMP trick: find s in (s+s) excluding positions 0 and n
        String doubled = s + s;
        String search = doubled.substring(1, doubled.length() - 1); // remove first and last char
        return search.contains(s); // O(n²) using built-in, or O(n) with KMP
        // Alternative O(n): use KMP to find s in doubled[1..2n-2]
    }
    // O(n) LPS approach:
    static boolean repeatedSubstringKMP(String s) {
        int n = s.length();
        int[] lps = buildLPS(s);
        int len = lps[n-1]; // longest proper prefix=suffix of whole s
        // If len > 0 and n % (n-len) == 0: s is made of repeating unit of length (n-len)
        return len > 0 && n % (n - len) == 0;
    }
    static int[] buildLPS(String p) {
        int m=p.length(); int[] lps=new int[m]; int len=0, i=1;
        while(i<m){if(p.charAt(i)==p.charAt(len)){lps[i]=len+1;len++;i++;}else{if(len>0)len=lps[len-1];else{lps[i]=0;i++;}}}
        return lps;
    }
    public static void main(String[] args) {
        System.out.println(repeatedSubstringPattern("abab"));         // true
        System.out.println(repeatedSubstringPattern("aba"));          // false
        System.out.println(repeatedSubstringKMP("abcabcabcabc"));    // true (O(n))
        System.out.println("KMP O(n): lps[n-1]>0 AND n%(n-lps[n-1])==0");
    }
}

