public class ShortestPalindrome {
    public static String shortestPalindrome(String s) {
        if (s.length() <= 1) return s;
        // Key insight: find longest palindromic prefix
        // Use KMP on s + '#' + reverse(s)
        // The LPS of this combined string gives longest palindromic prefix length
        String rev = new StringBuilder(s).reverse().toString();
        String combined = s + "#" + rev; // '#' prevents overlap
        int[] lps = buildLPS(combined);
        int palindromeLen = lps[combined.length() - 1];
        // Add reverse of non-palindromic suffix to front
        return rev.substring(0, s.length() - palindromeLen) + s;
    }
    static int[] buildLPS(String p) {
        int m=p.length(); int[] lps=new int[m]; int len=0, i=1;
        while(i<m){if(p.charAt(i)==p.charAt(len)){lps[i]=len+1;len++;i++;}else{if(len>0)len=lps[len-1];else{lps[i]=0;i++;}}}
        return lps;
    }
    public static void main(String[] args) {
        System.out.println(shortestPalindrome("aacecaaa")); // aaacecaaa
        System.out.println(shortestPalindrome("abcd"));     // dcbabcd
        System.out.println(shortestPalindrome(""));          // (empty)
        System.out.println("O(n) using KMP on s+'#'+reverse(s)");
    }
}

