public class RabinKarp {
    static final long BASE = 31, MOD = 1_000_000_007L;
    public static int search(String text, String pattern) {
        int n=text.length(), m=pattern.length();
        if(m>n) return -1;
        // Compute pattern hash and first window hash:
        long patHash=0, winHash=0, power=1;
        for(int i=0;i<m;i++) {
            patHash=(patHash*BASE + (pattern.charAt(i)-'a'+1))%MOD;
            winHash=(winHash*BASE + (text.charAt(i)-'a'+1))%MOD;
            if(i>0) power=power*BASE%MOD;
        }
        if(patHash==winHash && text.substring(0,m).equals(pattern)) return 0;
        // Slide window:
        for(int i=1; i<=n-m; i++) {
            winHash=(winHash - (text.charAt(i-1)-'a'+1)*power%MOD+MOD)%MOD;
            winHash=(winHash*BASE + (text.charAt(i+m-1)-'a'+1))%MOD;
            if(winHash==patHash && text.substring(i,i+m).equals(pattern)) return i;
        }
        return -1;
    }
    public static void main(String[] args) {
        System.out.println(search("hello world", "world")); // 6
        System.out.println(search("AABAAB", "AABAAB"));     // 0
        System.out.println(search("abc", "def"));           // -1
        System.out.println("Rabin-Karp: O(n+m) average, O(nm) worst (hash collisions)");
        System.out.println("Use MOD to prevent overflow; verify on hash match (avoid false positives)");
    }
}

