    static int[] buildLPS(String p){
        int m=p.length(); int[] lps=new int[m]; int len=0,i=1;
        while(i<m){if(p.charAt(i)==p.charAt(len)){lps[i]=len+1;len++;i++;}else{if(len>0)len=lps[len-1];else{lps[i]=0;i++;}}}
        return lps;
    }
    static boolean kmpContains(String text, String pattern){
        int n=text.length(),m=pattern.length();
        int[] lps=buildLPS(pattern); int i=0,j=0;
        while(i<n){if(text.charAt(i)==pattern.charAt(j)){i++;j++;}if(j==m)return true;else if(i<n&&text.charAt(i)!=pattern.charAt(j)){if(j>0)j=lps[j-1];else i++;}}
        return false;
    }
    public static boolean searchRightOrDown(char[][] grid, String word) {
        int rows=grid.length, cols=grid[0].length;
        // Search each row (left to right):
        for(int r=0; r<rows; r++){
            StringBuilder row=new StringBuilder();
            for(char c: grid[r]) row.append(c);
            if(kmpContains(row.toString(), word)) return true;
        }
        // Search each column (top to bottom):
        for(int c=0; c<cols; c++){
            StringBuilder col=new StringBuilder();
            for(int r=0; r<rows; r++) col.append(grid[r][c]);
            if(kmpContains(col.toString(), word)) return true;
        }
        return false;
    }
